CREATE FUNCTION "public"."cancel_saved_games_for_event_block"() RETURNS trigger LANGUAGE plpgsql SECURITY DEFINER SET search_path TO '' AS $$ DECLARE v_table_id uuid; BEGIN FOR v_table_id IN SELECT id FROM public.tables WHERE room_id = NEW.room_id ORDER BY id LOOP PERFORM pg_catalog.pg_advisory_xact_lock(pg_catalog.hashtextextended(v_table_id::text, 0)); END LOOP; UPDATE public.saved_games AS saved SET status = 'cancelled', updated_at = now() FROM public.tables AS game_table WHERE saved.table_id = game_table.id AND game_table.room_id = NEW.room_id AND saved.status = 'active' AND NEW.date BETWEEN saved.start_date AND saved.end_date; RETURN NEW; END; $$;
